use crate::body::RigidBodySet;
use crate::contact::ContactTracker;
use crate::math::Vec2;
use crate::solver_body::SolverBodySet;

/// Last-step diagnostics for debugging impulse spikes (WASM / tests).
#[derive(Clone, Copy, Debug, Default)]
pub struct SolverDiagnostics {
    pub max_normal_impulse: f32,
    pub max_normal_collider_a: u32,
    pub max_normal_collider_b: u32,
    pub max_tangent_impulse: f32,
    pub total_impulse_magnitude: f32,
    pub num_clamped_velocities: u32,
    /// Sum of squared linear velocity deltas applied during warm-start (diagnostic).
    pub warmstart_linear_delta_sq: f32,
}

/// Spring-based ERP/CFM coefficients for contact softness
pub struct ContactSpringCoefficients {
    pub natural_frequency: f32,
    pub damping_ratio: f32,
}

impl ContactSpringCoefficients {
    pub fn default_contact() -> Self {
        Self {
            natural_frequency: 22.0,
            damping_ratio: 4.0,
        }
    }

    pub fn erp_inv_dt(&self, dt: f32) -> f32 {
        let ang_freq = self.natural_frequency * 2.0 * std::f32::consts::PI;
        ang_freq / (dt * ang_freq + 2.0 * self.damping_ratio)
    }

    pub fn cfm_factor(&self, dt: f32) -> f32 {
        let erp = self.erp(dt);
        if erp == 0.0 {
            return 1.0;
        }
        let inv_erp_minus_one = 1.0 / erp - 1.0;
        let denom = (1.0 + inv_erp_minus_one) * 4.0 * self.damping_ratio * self.damping_ratio;
        if denom == 0.0 {
            return 1.0;
        }
        let cfm_coeff = (inv_erp_minus_one * inv_erp_minus_one) / denom;
        1.0 / (1.0 + cfm_coeff)
    }

    fn erp(&self, dt: f32) -> f32 {
        let ang_freq = self.natural_frequency * 2.0 * std::f32::consts::PI;
        ang_freq * dt / (dt * ang_freq + 2.0 * self.damping_ratio)
    }
}

/// Per-contact-point normal constraint
#[derive(Clone, Debug)]
pub struct ContactConstraintNormal {
    pub body_a: usize,
    pub body_b: usize,
    pub normal: Vec2,
    pub torque_dir_a: f32,
    pub torque_dir_b: f32,
    pub ii_torque_dir_a: f32,
    pub ii_torque_dir_b: f32,
    pub rhs: f32,
    pub rhs_wo_bias: f32,
    pub impulse: f32,
    pub projected_mass: f32,
    pub cfm_factor: f32,
    /// Multiplies spring CFM in [`ContactConstraintSet::update`] (mass‑ratio softening).
    pub cfm_mass_ratio_scale: f32,
    pub r_mat_diag: f32,
    pub r_mat_offdiag: f32,
    pub penetration: f32,
    /// Local contact point on body A (for penetration recomputation during substepping)
    pub local_a: Vec2,
    /// Local contact point on body B
    pub local_b: Vec2,
    /// Precomputed offset so that dist = dist_offset + (world_b - world_a).dot(normal)
    /// and penetration = max(0, -dist)
    pub dist_offset: f32,
    /// Restitution velocity (set once during build, preserved across updates)
    pub normal_vel: f32,
}

/// Per-contact-point tangent (friction) constraint
#[derive(Clone, Debug)]
pub struct ContactConstraintTangent {
    pub body_a: usize,
    pub body_b: usize,
    pub tangent: Vec2,
    pub torque_dir_a: f32,
    pub torque_dir_b: f32,
    pub ii_torque_dir_a: f32,
    pub ii_torque_dir_b: f32,
    pub rhs: f32,
    pub impulse: f32,
    pub projected_mass: f32,
    /// Kinetic (dynamic) friction coefficient — used when sliding
    pub friction_coeff: f32,
    /// Static friction coefficient — Coulomb threshold before sliding begins
    pub static_friction_coeff: f32,
    pub normal_idx: usize,
}

/// A group of constraints for a single contact pair
#[derive(Debug)]
pub struct ContactPairConstraints {
    pub collider_a: crate::collider::ColliderHandle,
    pub collider_b: crate::collider::ColliderHandle,
    pub normals: Vec<ContactConstraintNormal>,
    pub tangents: Vec<ContactConstraintTangent>,
    /// When false, solve normal constraints sequentially (avoids ill‑conditioned 2×2 blocks at corners).
    pub use_block_solver_for_pair: bool,
}

/// Full constraint set for all active contact pairs
pub struct ContactConstraintSet {
    pub pairs: Vec<ContactPairConstraints>,
    pub spring: ContactSpringCoefficients,
    pub allowed_linear_error: f32,
    pub max_corrective_velocity: f32,
    pub baumgarte_factor: f32,
    /// Hard clamp on linear velocity magnitude after each PGS pass (m/s).
    pub max_solver_linear_velocity: f32,
    /// Hard clamp on angular velocity magnitude after each PGS pass (rad/s).
    pub max_solver_angular_velocity: f32,
    /// Clamp on |Jv + rhs| in PGS rows (derived from [`Self::max_solver_linear_velocity`]).
    pub dvel_limit: f32,
    /// Impulse under-relaxation in `(0, 1]` (SOR on Δλ). Stabilizes stiff contact without post-hoc |v| clamps.
    pub pgs_relaxation: f32,
    /// Filled at end of [`crate::velocity_solver::solve`].
    pub last_diagnostics: SolverDiagnostics,
}

impl ContactConstraintSet {
    pub fn new() -> Self {
        Self {
            pairs: Vec::new(),
            spring: ContactSpringCoefficients::default_contact(),
            allowed_linear_error: 0.001,
            max_corrective_velocity: 50.0,
            baumgarte_factor: 0.01,
            max_solver_linear_velocity: f32::INFINITY,
            max_solver_angular_velocity: f32::INFINITY,
            dvel_limit: f32::INFINITY,
            pgs_relaxation: 0.88,
            last_diagnostics: SolverDiagnostics::default(),
        }
    }

    pub fn set_position_correction(&mut self, beta: f32, max_velocity: f32) {
        self.baumgarte_factor = beta;
        self.max_corrective_velocity = max_velocity;
    }

    pub fn set_spring_coefficients(&mut self, natural_frequency: f32, damping_ratio: f32) {
        self.spring.natural_frequency = natural_frequency;
        self.spring.damping_ratio = damping_ratio;
    }

    /// Reset PGS λ accumulators without changing velocities (each solver substep).
    pub fn clear_impulses(&mut self) {
        for pair in &mut self.pairs {
            for n in &mut pair.normals {
                n.impulse = 0.0;
            }
            for t in &mut pair.tangents {
                t.impulse = 0.0;
            }
        }
    }

    /// Build constraints from contact pairs and solver bodies
    pub fn build_from_pairs(
        &mut self,
        tracker: &ContactTracker,
        colliders: &crate::collider::ColliderSet,
        bodies: &RigidBodySet,
        solver_bodies: &SolverBodySet,
        dt: f32,
        block_solver: bool,
    ) {
        self.pairs.clear();

        self.dvel_limit = if self.max_solver_linear_velocity.is_finite()
            && self.max_solver_linear_velocity > 0.0
        {
            (self.max_solver_linear_velocity * 2.0).max(1.0)
        } else {
            f32::INFINITY
        };

        let cfm_factor = self.spring.cfm_factor(dt);
        let max_restitution_vel = if self.max_solver_linear_velocity.is_finite()
            && self.max_solver_linear_velocity > 0.0
        {
            self.max_solver_linear_velocity * 0.5
        } else {
            f32::INFINITY
        };

        // PGS convergence depends on constraint order; `HashMap` iteration is randomized per process,
        // which made integration tests flaky. Sort by collider handles for a stable order.
        let mut sorted_pairs: Vec<&crate::contact::ContactPair> = tracker
            .pairs()
            .filter(|p| !p.manifold.contacts.is_empty())
            .collect();
        sorted_pairs.sort_by(|a, b| {
            a.collider_a
                .cmp(&b.collider_a)
                .then_with(|| a.collider_b.cmp(&b.collider_b))
        });

        for pair in sorted_pairs {
            let col_a = match colliders.get(pair.collider_a) {
                Some(c) => c,
                None => continue,
            };
            let col_b = match colliders.get(pair.collider_b) {
                Some(c) => c,
                None => continue,
            };

            let Some(ha) = col_a.parent else {
                continue;
            };
            let Some(hb) = col_b.parent else {
                continue;
            };
            if bodies.get(ha).is_none() || bodies.get(hb).is_none() {
                continue;
            }

            let body_a_idx = ha.index();
            let body_b_idx = hb.index();
            if body_a_idx >= solver_bodies.capacity || body_b_idx >= solver_bodies.capacity {
                continue;
            }

            let pose_a0 = solver_bodies.pose(body_a_idx);
            let pose_b0 = solver_bodies.pose(body_b_idx);
            let mass_ratio = if pose_a0.inv_mass > 1e-20 && pose_b0.inv_mass > 1e-20 {
                let ma = 1.0 / pose_a0.inv_mass;
                let mb = 1.0 / pose_b0.inv_mass;
                ma.max(mb) / ma.min(mb)
            } else {
                1.0
            };
            let pair_cfm_scale = if mass_ratio > 100.0 { 0.8 } else { 1.0 };
            let pair_cfm = cfm_factor * pair_cfm_scale;

            let raw_n = pair.manifold.normal;
            if raw_n.x.is_nan() || raw_n.y.is_nan() {
                continue;
            }
            let Some(normal) = raw_n.try_normalize() else {
                continue;
            };
            let tangent = normal.perp();
            // Box2D-style geometric mean for friction (behaves well for stacks / mixed materials).
            let friction = mix_friction_coeff(col_a.friction, col_b.friction);
            let static_friction = mix_friction_coeff(col_a.static_friction, col_b.static_friction);
            let restitution = col_a.restitution.min(col_b.restitution);

            let mut normals = Vec::new();
            let mut tangents = Vec::new();

            for (ci, contact) in pair.manifold.contacts.iter().enumerate() {
                let pose_a = solver_bodies.pose(body_a_idx);
                let pose_b = solver_bodies.pose(body_b_idx);

                let r_a = pose_a.rotation.mul_vec(contact.local_a);
                let r_b = pose_b.rotation.mul_vec(contact.local_b);

                let torque_a = r_a.cross(normal);
                let torque_b = r_b.cross(-normal);

                let ii_td_a = pose_a.inv_inertia * torque_a;
                let ii_td_b = pose_b.inv_inertia * torque_b;

                let inv_mass_sum = pose_a.inv_mass + pose_b.inv_mass;
                let k = inv_mass_sum + torque_a * ii_td_a + torque_b * ii_td_b;
                let proj_mass = if k > 0.0 { 1.0 / k } else { 0.0 };

                // Store effective mass (k) for block solver, not projected mass.
                // The block solver solves K_eff * Δλ = -dvel, so diagonal must be k.
                let r_mat_diag = k;
                let r_mat_offdiag = 0.0;

                let vel_a = solver_bodies.vel(body_a_idx);
                let vel_b = solver_bodies.vel(body_b_idx);
                let v_a = vel_a.linear + Vec2::new(-vel_a.angular * r_a.y, vel_a.angular * r_a.x);
                let v_b = vel_b.linear + Vec2::new(-vel_b.angular * r_b.y, vel_b.angular * r_b.x);
                let rel_vel = v_b - v_a;
                let normal_vel = rel_vel.dot(normal);

                let is_new = contact.is_new;
                let is_bouncy = if is_new {
                    restitution > 0.0
                } else {
                    restitution >= 1.0
                };

                // rhs_wo_bias stores the restitution velocity target.
                // It persists across update() calls so restitution isn't lost.
                let rhs_wo_bias = if is_bouncy {
                    let nv = normal_vel.min(0.0);
                    // New contacts with partial restitution: ignore micro-impacts so resting
                    // stacks do not get continuous bounce / spin injection from solver jitter.
                    let nv_eff = if is_new && restitution > 0.0 && restitution < 1.0 && nv > -0.35 {
                        0.0
                    } else {
                        nv
                    };
                    let r = restitution * nv_eff;
                    if max_restitution_vel.is_finite() {
                        r.clamp(-max_restitution_vel, 0.0)
                    } else {
                        r.min(0.0)
                    }
                } else {
                    0.0
                };

                let rhs = rhs_wo_bias;

                // Compute dist_offset for penetration recomputation during substepping.
                // Convention: dist = dist_offset + (world_b - world_a).dot(normal)
                //             penetration = max(0, -dist)
                // At build time: dist = -contact.penetration
                let world_a = pose_a.translation + r_a;
                let world_b = pose_b.translation + r_b;
                let initial_gap = (world_b - world_a).dot(normal);
                let dist_offset = -contact.penetration - initial_gap;

                normals.push(ContactConstraintNormal {
                    body_a: body_a_idx,
                    body_b: body_b_idx,
                    normal,
                    torque_dir_a: torque_a,
                    torque_dir_b: torque_b,
                    ii_torque_dir_a: ii_td_a,
                    ii_torque_dir_b: ii_td_b,
                    rhs,
                    rhs_wo_bias,
                    impulse: 0.0,
                    projected_mass: proj_mass,
                    cfm_factor: pair_cfm,
                    cfm_mass_ratio_scale: pair_cfm_scale,
                    r_mat_diag,
                    r_mat_offdiag,
                    penetration: contact.penetration,
                    local_a: contact.local_a,
                    local_b: contact.local_b,
                    dist_offset,
                    normal_vel: rhs_wo_bias,
                });

                let rt_a = r_a.cross(tangent);
                let rt_b = r_b.cross(tangent);
                let ii_rt_a = pose_a.inv_inertia * rt_a;
                let ii_rt_b = pose_b.inv_inertia * rt_b;
                let k_t = inv_mass_sum + rt_a * ii_rt_a + rt_b * ii_rt_b;
                let proj_mass_t = if k_t > 0.0 { 1.0 / k_t } else { 0.0 };

                let _tangent_vel = rel_vel.dot(tangent);
                tangents.push(ContactConstraintTangent {
                    body_a: body_a_idx,
                    body_b: body_b_idx,
                    tangent,
                    torque_dir_a: rt_a,
                    torque_dir_b: rt_b,
                    ii_torque_dir_a: ii_rt_a,
                    ii_torque_dir_b: ii_rt_b,
                    rhs: 0.0,
                    impulse: 0.0,
                    projected_mass: proj_mass_t,
                    friction_coeff: friction,
                    static_friction_coeff: static_friction,
                    normal_idx: ci,
                });
            }

            let mut use_block_for_pair = block_solver && normals.len() >= 2;
            // Wide contact span + block solve fights rotation mainly on non‑cuboid polygons.
            // OBB–OBB pairs legitimately have large lever arms along an edge; keep block solver on.
            let poly_corner_risk = shape_is_non_quad_polygon(&col_a.shape)
                || shape_is_non_quad_polygon(&col_b.shape);
            if use_block_for_pair && poly_corner_risk {
                let pose_a0 = solver_bodies.pose(body_a_idx);
                let c0 = &pair.manifold.contacts[0];
                let c1 = &pair.manifold.contacts[1];
                let r0 = pose_a0.rotation.mul_vec(c0.local_a);
                let r1 = pose_a0.rotation.mul_vec(c1.local_a);
                let span = (r0 - r1).length();
                let mtd = pair.manifold.max_penetration().max(0.02);
                let span_limit = (mtd * 4.0).max(0.08);
                if span > span_limit {
                    use_block_for_pair = false;
                }
            }

            if use_block_for_pair {
                for i in (0..normals.len().saturating_sub(1)).step_by(2) {
                    let na = &normals[i];
                    let nb = &normals[i + 1];
                    let pose_a = solver_bodies.pose(na.body_a);
                    let pose_b = solver_bodies.pose(na.body_b);
                    let inv_mass_sum = pose_a.inv_mass + pose_b.inv_mass;
                    let offdiag = inv_mass_sum
                        + na.torque_dir_a * pose_a.inv_inertia * nb.torque_dir_a
                        + na.torque_dir_b * pose_b.inv_inertia * nb.torque_dir_b;
                    normals[i].r_mat_offdiag = offdiag;
                    normals[i + 1].r_mat_offdiag = offdiag;
                }
            }

            self.pairs.push(ContactPairConstraints {
                collider_a: pair.collider_a,
                collider_b: pair.collider_b,
                normals,
                tangents,
                use_block_solver_for_pair: use_block_for_pair,
            });
        }
    }

    /// Update constraints: recompute penetration from current solver body poses,
    /// then recompute RHS bias. This is critical for substepping — positions change
    /// between substeps, so penetration must be refreshed.
    ///
    /// `integration_dt` is the solver substep length (used for CFM / spring ERP).
    /// `baumgarte_ref_dt` is kept for API compatibility; Baumgarte is not applied here
    /// (spring ERP handles position correction without double-counting).
    pub fn update(
        &mut self,
        solver_bodies: &SolverBodySet,
        integration_dt: f32,
        _baumgarte_ref_dt: f32,
    ) {
        let cfm_factor = self.spring.cfm_factor(integration_dt);
        let erp_inv_dt = self.spring.erp_inv_dt(integration_dt);

        for pair in &mut self.pairs {
            for n in &mut pair.normals {
                // Recompute penetration from current solver body poses
                let pose_a = solver_bodies.pose(n.body_a);
                let pose_b = solver_bodies.pose(n.body_b);
                let r_a = pose_a.rotation.mul_vec(n.local_a);
                let r_b = pose_b.rotation.mul_vec(n.local_b);
                let world_a = pose_a.translation + r_a;
                let world_b = pose_b.translation + r_b;
                let current_gap = (world_b - world_a).dot(n.normal);
                let dist = n.dist_offset + current_gap;
                n.penetration = (-dist).max(0.0);

                // Recompute geometric terms (torque directions) from new poses
                n.torque_dir_a = r_a.cross(n.normal);
                n.torque_dir_b = r_b.cross(-n.normal);
                n.ii_torque_dir_a = pose_a.inv_inertia * n.torque_dir_a;
                n.ii_torque_dir_b = pose_b.inv_inertia * n.torque_dir_b;

                // Recompute projected mass
                let inv_mass_sum = pose_a.inv_mass + pose_b.inv_mass;
                let k = inv_mass_sum
                    + n.torque_dir_a * n.ii_torque_dir_a
                    + n.torque_dir_b * n.ii_torque_dir_b;
                n.projected_mass = if k > 0.0 { 1.0 / k } else { 0.0 };
                n.r_mat_diag = k;

                // rhs_wo_bias: restitution target only. Speculative "separation velocity" from a
                // positive gap injects noise on resting stacks (micro-separation jitter).
                n.rhs_wo_bias = n.normal_vel;

                // Penetration bias: spring ERP only (no separate Baumgarte — avoids double correction).
                // Restitution target `rhs_wo_bias` and spring bias both push separation; take the
                // stricter (more negative) so we do not add energy from stacking both terms.
                let allowed = self.allowed_linear_error;
                let raw_spring = (dist + allowed) * erp_inv_dt;
                let spring_bias = clamp_nonpos_bias(raw_spring, self.max_corrective_velocity);
                let combined = n.rhs_wo_bias.min(spring_bias);
                n.rhs = clamp_nonpos_bias(combined, self.max_corrective_velocity);
                n.cfm_factor = cfm_factor * n.cfm_mass_ratio_scale;
            }

            // 2×2 block effective-mass off-diagonals (not per-normal); must track refreshed normals.
            if pair.use_block_solver_for_pair {
                for i in (0..pair.normals.len().saturating_sub(1)).step_by(2) {
                    let (left, right) = pair.normals.split_at_mut(i + 1);
                    let na = &left[i];
                    let nb = &right[0];
                    let pose_a = solver_bodies.pose(na.body_a);
                    let pose_b = solver_bodies.pose(na.body_b);
                    let inv_mass_sum = pose_a.inv_mass + pose_b.inv_mass;
                    let offdiag = inv_mass_sum
                        + na.torque_dir_a * pose_a.inv_inertia * nb.torque_dir_a
                        + na.torque_dir_b * pose_b.inv_inertia * nb.torque_dir_b;
                    left[i].r_mat_offdiag = offdiag;
                    right[0].r_mat_offdiag = offdiag;
                }
            }

            // Friction rows share contact points with normals; refresh lever arms when poses move.
            for ti in 0..pair.tangents.len() {
                let ni = pair.tangents[ti].normal_idx;
                if ni >= pair.normals.len() {
                    continue;
                }
                let tangent_dir = pair.tangents[ti].tangent;
                let nr = &pair.normals[ni];
                let pose_a = solver_bodies.pose(nr.body_a);
                let pose_b = solver_bodies.pose(nr.body_b);
                let r_a = pose_a.rotation.mul_vec(nr.local_a);
                let r_b = pose_b.rotation.mul_vec(nr.local_b);
                let rt_a = r_a.cross(tangent_dir);
                let rt_b = r_b.cross(tangent_dir);
                let t = &mut pair.tangents[ti];
                t.torque_dir_a = rt_a;
                t.torque_dir_b = rt_b;
                t.ii_torque_dir_a = pose_a.inv_inertia * rt_a;
                t.ii_torque_dir_b = pose_b.inv_inertia * rt_b;
                let inv_mass_sum = pose_a.inv_mass + pose_b.inv_mass;
                let k_t = inv_mass_sum + rt_a * t.ii_torque_dir_a + rt_b * t.ii_torque_dir_b;
                t.projected_mass = if k_t > 0.0 { 1.0 / k_t } else { 0.0 };
            }
        }
    }

    /// Solve all constraints with bias (main PGS iterations)
    pub fn solve(
        &mut self,
        solver_bodies: &mut SolverBodySet,
        block_solver: bool,
        clamp_count: &mut u32,
    ) {
        let lim = self.dvel_limit;
        let relax = self.pgs_relaxation.clamp(0.05, 1.0);
        for pi in 0..self.pairs.len() {
            let pair = &mut self.pairs[pi];

            let use_block = block_solver && pair.use_block_solver_for_pair && pair.normals.len() >= 2;
            if use_block {
                for i in (0..pair.normals.len().saturating_sub(1)).step_by(2) {
                    let (left, right) = pair.normals.split_at_mut(i + 1);
                    solve_normal_pair(solver_bodies, &mut left[i], &mut right[0], lim, relax);
                }
                if pair.normals.len() % 2 == 1 {
                    let last = pair.normals.len() - 1;
                    solve_normal_single(solver_bodies, &mut pair.normals[last], lim, relax);
                }
            } else {
                for n in &mut pair.normals {
                    solve_normal_single(solver_bodies, n, lim, relax);
                }
            }

            for ti in 0..pair.tangents.len() {
                let normal_impulse = if pair.tangents[ti].normal_idx < pair.normals.len() {
                    pair.normals[pair.tangents[ti].normal_idx].impulse
                } else {
                    0.0
                };
                solve_tangent(solver_bodies, &mut pair.tangents[ti], normal_impulse, lim, relax);
            }
        }

        self.clamp_solver_velocities(solver_bodies, clamp_count);
    }

    fn clamp_solver_velocities(&self, solver_bodies: &mut SolverBodySet, clamp_count: &mut u32) {
        if self.pairs.is_empty() {
            return;
        }
        let max_lin = if self.max_solver_linear_velocity.is_finite()
            && self.max_solver_linear_velocity > 0.0
        {
            Some(self.max_solver_linear_velocity)
        } else {
            None
        };
        let max_ang = if self.max_solver_angular_velocity.is_finite()
            && self.max_solver_angular_velocity > 0.0
        {
            Some(self.max_solver_angular_velocity)
        } else {
            None
        };
        if max_lin.is_none() && max_ang.is_none() {
            return;
        }
        let mut constrained = vec![false; solver_bodies.capacity];
        for pair in &self.pairs {
            for n in &pair.normals {
                if n.body_a < constrained.len() {
                    constrained[n.body_a] = true;
                }
                if n.body_b < constrained.len() {
                    constrained[n.body_b] = true;
                }
            }
        }
        for i in 0..solver_bodies.capacity {
            let vel = &mut solver_bodies.vels[i];
            if vel.linear.x.is_nan() || vel.linear.y.is_nan() {
                vel.linear = Vec2::zero();
            } else if constrained[i] {
                if let Some(cap) = max_lin {
                    let lin_len = vel.linear.length();
                    if lin_len > cap {
                        vel.linear = vel.linear * (cap / lin_len.max(1e-20));
                        *clamp_count += 1;
                    }
                }
            }
            if vel.angular.is_nan() {
                vel.angular = 0.0;
            } else if constrained[i] {
                if let Some(cap) = max_ang {
                    if vel.angular.abs() > cap {
                        vel.angular = vel.angular.signum() * cap;
                        *clamp_count += 1;
                    }
                }
            }
        }
    }

    /// Snapshot impulse stats after the final PGS state (call once per frame after substeps).
    pub fn finalize_impulse_diagnostics(&mut self, clamp_events: u32) {
        let mut d = SolverDiagnostics {
            num_clamped_velocities: clamp_events,
            ..Default::default()
        };
        for pair in &self.pairs {
            for n in &pair.normals {
                if n.impulse > d.max_normal_impulse {
                    d.max_normal_impulse = n.impulse;
                    d.max_normal_collider_a = pair.collider_a.0;
                    d.max_normal_collider_b = pair.collider_b.0;
                }
                d.total_impulse_magnitude += n.impulse.abs();
            }
            for t in &pair.tangents {
                let at = t.impulse.abs();
                d.max_tangent_impulse = d.max_tangent_impulse.max(at);
                d.total_impulse_magnitude += at;
            }
        }
        d.warmstart_linear_delta_sq = 0.0;
        self.last_diagnostics = d;
    }

    /// Rebuild constraint RHS from current solver velocities.
    /// Call this between PGS iterations to keep the RHS fresh.
    pub fn rebuild_rhs(&mut self, solver_bodies: &SolverBodySet, dt: f32) {
        let inv_dt = 1.0 / dt;
        let beta = self.baumgarte_factor;

        for pair in &mut self.pairs {
            for n in &mut pair.normals {
                let vel_a = solver_bodies.vel(n.body_a);
                let vel_b = solver_bodies.vel(n.body_b);
                let normal_vel = n.normal.dot(vel_b.linear - vel_a.linear)
                    + n.torque_dir_b * vel_b.angular
                    - n.torque_dir_a * vel_a.angular;

                let slop = self.allowed_linear_error;
                let dist = -(n.penetration - slop).max(0.0);
                let rhs_bias = if dist < 0.0 {
                    clamp_nonpos_bias(dist * beta * inv_dt, self.max_corrective_velocity)
                } else {
                    0.0
                };

                n.rhs_wo_bias = normal_vel;
                // rhs contains ONLY bias — relative velocity computed in solve
                n.rhs = rhs_bias;
            }
        }
    }
}

impl Default for ContactConstraintSet {
    fn default() -> Self {
        Self::new()
    }
}

#[inline]
fn shape_is_non_quad_polygon(shape: &crate::collider::Shape) -> bool {
    matches!(
        shape,
        crate::collider::Shape::Polygon { vertices } if vertices.len() != 4
    )
}

/// Clamp non-positive bias; if `max_mag` is not finite, only enforce `≤ 0` (no artificial ceiling).
#[inline]
fn clamp_nonpos_bias(v: f32, max_mag: f32) -> f32 {
    if max_mag.is_finite() {
        v.clamp(-max_mag, 0.0)
    } else {
        v.min(0.0)
    }
}

/// Friction combine: arithmetic mean, matching Rapier’s default `CoefficientCombineRule::Average`.
#[inline]
fn mix_friction_coeff(a: f32, b: f32) -> f32 {
    let a = a.max(0.0);
    let b = b.max(0.0);
    (a + b) * 0.5
}

// ---- Free functions to avoid borrow checker issues ----

fn solve_normal_single(
    solver_bodies: &mut SolverBodySet,
    n: &mut ContactConstraintNormal,
    dvel_limit: f32,
    relax: f32,
) {
    let ba = n.body_a;
    let bb = n.body_b;
    let normal = n.normal;
    let td_a = n.torque_dir_a;
    let td_b = n.torque_dir_b;
    let ii_a = n.ii_torque_dir_a;
    let ii_b = n.ii_torque_dir_b;
    let rhs = n.rhs;
    let pm = n.projected_mass;

    // NaN guard on constraint data
    if normal.x.is_nan() || normal.y.is_nan() || pm.is_nan() || rhs.is_nan() {
        return;
    }

    let va_lin = solver_bodies.vel(ba).linear;
    let va_ang = solver_bodies.vel(ba).angular;
    let vb_lin = solver_bodies.vel(bb).linear;
    let vb_ang = solver_bodies.vel(bb).angular;

    // NaN guard on velocities
    if va_lin.x.is_nan()
        || va_lin.y.is_nan()
        || va_ang.is_nan()
        || vb_lin.x.is_nan()
        || vb_lin.y.is_nan()
        || vb_ang.is_nan()
    {
        return;
    }

    let dvel_uncapped = normal.dot(vb_lin - va_lin) - td_a * va_ang - td_b * vb_ang + rhs;
    let dvel = if dvel_limit.is_finite() {
        dvel_uncapped.clamp(-dvel_limit, dvel_limit)
    } else {
        dvel_uncapped
    };

    let cf = n.cfm_factor;
    let gs_target = (cf * (n.impulse - pm * dvel)).max(0.0);
    let dlambda = (gs_target - n.impulse) * relax;
    n.impulse += dlambda;

    let im_a = solver_bodies.pose(ba).inv_mass;
    let im_b = solver_bodies.pose(bb).inv_mass;

    let va = solver_bodies.vel_mut(ba);
    va.linear -= normal * (dlambda * im_a);
    va.angular -= ii_a * dlambda;

    let vb = solver_bodies.vel_mut(bb);
    vb.linear += normal * (dlambda * im_b);
    vb.angular -= ii_b * dlambda;
}

fn solve_normal_pair(
    solver_bodies: &mut SolverBodySet,
    na: &mut ContactConstraintNormal,
    nb: &mut ContactConstraintNormal,
    dvel_limit: f32,
    relax: f32,
) {
    let ba = na.body_a;
    let bb = na.body_b;
    let na_normal = na.normal;
    let nb_normal = nb.normal;
    let na_td_a = na.torque_dir_a;
    let na_td_b = na.torque_dir_b;
    let na_ii_a = na.ii_torque_dir_a;
    let na_ii_b = na.ii_torque_dir_b;
    let nb_ii_a = nb.ii_torque_dir_a;
    let nb_ii_b = nb.ii_torque_dir_b;
    let na_rhs = na.rhs;
    let nb_rhs = nb.rhs;
    let na_pm = na.projected_mass;
    let nb_pm = nb.projected_mass;
    let k00 = na.r_mat_diag;
    let k11 = nb.r_mat_diag;
    let k01 = na.r_mat_offdiag;
    let k10 = k01;

    if na_normal.x.is_nan()
        || na_normal.y.is_nan()
        || nb_normal.x.is_nan()
        || nb_normal.y.is_nan()
        || na_pm.is_nan()
        || nb_pm.is_nan()
        || na_rhs.is_nan()
        || nb_rhs.is_nan()
    {
        return;
    }

    let va_lin = solver_bodies.vel(ba).linear;
    let va_ang = solver_bodies.vel(ba).angular;
    let vb_lin = solver_bodies.vel(bb).linear;
    let vb_ang = solver_bodies.vel(bb).angular;

    if va_lin.x.is_nan()
        || va_lin.y.is_nan()
        || va_ang.is_nan()
        || vb_lin.x.is_nan()
        || vb_lin.y.is_nan()
        || vb_ang.is_nan()
    {
        return;
    }

    let dvel_a = na_normal.dot(vb_lin - va_lin) - na_td_a * va_ang - na_td_b * vb_ang + na_rhs;
    let nb_td_a = nb.torque_dir_a;
    let nb_td_b = nb.torque_dir_b;
    let dvel_b = nb_normal.dot(vb_lin - va_lin) - nb_td_a * va_ang - nb_td_b * vb_ang + nb_rhs;

    let dvel_a = if dvel_limit.is_finite() {
        dvel_a.clamp(-dvel_limit, dvel_limit)
    } else {
        dvel_a
    };
    let dvel_b = if dvel_limit.is_finite() {
        dvel_b.clamp(-dvel_limit, dvel_limit)
    } else {
        dvel_b
    };

    let det = k00 * k11 - k01 * k10;
    let x: (f32, f32);

    // Scale-independent well-conditioning: when k01 ≈ sqrt(k00*k11), det is tiny
    // relative to k00*k11 and inv_det amplifies dvel noise into huge impulses.
    // Box2D-style bound on (k00*k11)/det; fall back to sequential 1×1 solves otherwise.
    let k_max_condition = 100.0;
    let is_well_conditioned = det > 0.0 && (k00 * k11) < k_max_condition * det;

    if is_well_conditioned {
        let inv_det = 1.0 / det;
        let cf = na.cfm_factor;
        let cx = cf * (na.impulse - (k11 * dvel_a - k01 * dvel_b) * inv_det);
        let cy = cf * (nb.impulse - (-k10 * dvel_a + k00 * dvel_b) * inv_det);
        // After impulse deltas d0, d1, constraint "separation velocities" (same convention as
        // `dvel_*`) update as w = dvel - K·Δλ — used for LCP complementarity on inactive rows.
        let sep = |d0: f32, d1: f32| -> (f32, f32) {
            let w_a = dvel_a - k00 * d0 - k01 * d1;
            let w_b = dvel_b - k01 * d0 - k11 * d1;
            (w_a, w_b)
        };
        const SLACK_EPS: f32 = 1.0e-5;

        if cx >= 0.0 && cy >= 0.0 {
            x = (cx, cy);
        } else {
            // Joint unconstrained solution violates λ ≥ 0: project onto the LCP feasible set
            // (Box2D-style enumeration with separation checks — do not use decoupled λ signs alone).
            //
            // Face candidates use the same decoupled 1×1 PGS targets as before (`dvel / kii`); do not
            // fold `k01·λ` into that RHS here — `dvel` already reflects the current integrated
            // velocities for this PGS pass, and adding `k01·impulse` double-counted λ and caused
            // huge face impulses and tunneling in dense scenes.
            let xa_dec = na.cfm_factor * (na.impulse - dvel_a / k00);
            let yb_dec = nb.cfm_factor * (nb.impulse - dvel_b / k11);

            // 2) λ_a > 0, λ_b = 0 — need w_b ≥ 0 (inactive row b).
            let xa2 = xa_dec.max(0.0);
            let d0_2 = xa2 - na.impulse;
            let d1_2 = -nb.impulse;
            let (_, w_b2) = sep(d0_2, d1_2);
            if xa2 > SLACK_EPS && w_b2 >= -SLACK_EPS {
                x = (xa2, 0.0);
            } else {
                // 3) λ_a = 0, λ_b > 0 — need w_a ≥ 0.
                let yb3 = yb_dec.max(0.0);
                let d0_3 = -na.impulse;
                let d1_3 = yb3 - nb.impulse;
                let (w_a3, _) = sep(d0_3, d1_3);
                if yb3 > SLACK_EPS && w_a3 >= -SLACK_EPS {
                    x = (0.0, yb3);
                } else {
                    // 4) λ_a = λ_b = 0 — need w_a ≥ 0 and w_b ≥ 0.
                    let d0_4 = -na.impulse;
                    let d1_4 = -nb.impulse;
                    let (w_a4, w_b4) = sep(d0_4, d1_4);
                    if w_a4 >= -SLACK_EPS && w_b4 >= -SLACK_EPS {
                        x = (0.0, 0.0);
                    } else {
                        // No feasible vertex: fall back to sequential 1×1 (same as ill-conditioned path).
                        x = (
                            (na.impulse - na_pm * dvel_a).max(0.0),
                            (nb.impulse - nb_pm * dvel_b).max(0.0),
                        );
                    }
                }
            }
        }
    } else {
        // Fallback: solve independently
        x = (
            (na.impulse - na_pm * dvel_a).max(0.0),
            (nb.impulse - nb_pm * dvel_b).max(0.0),
        );
    }

    let x0 = x.0;
    let x1 = x.1;

    let d0 = (x0 - na.impulse) * relax;
    let d1 = (x1 - nb.impulse) * relax;
    na.impulse += d0;
    nb.impulse += d1;

    let im_a = solver_bodies.pose(ba).inv_mass;
    let im_b = solver_bodies.pose(bb).inv_mass;

    let va = solver_bodies.vel_mut(ba);
    va.linear -= (na_normal * d0 + nb_normal * d1) * im_a;
    va.angular -= na_ii_a * d0 + nb_ii_a * d1;

    let vb = solver_bodies.vel_mut(bb);
    vb.linear += (na_normal * d0 + nb_normal * d1) * im_b;
    vb.angular -= na_ii_b * d0 + nb_ii_b * d1;
}

// normal_impulse: accumulated normal impulse magnitude for this contact point (j in the article)
fn solve_tangent(
    solver_bodies: &mut SolverBodySet,
    t: &mut ContactConstraintTangent,
    normal_impulse: f32,
    dvel_limit: f32,
    relax: f32,
) {
    let ba = t.body_a;
    let bb = t.body_b;
    let tangent = t.tangent;
    let td_a = t.torque_dir_a;
    let td_b = t.torque_dir_b;
    let ii_a = t.ii_torque_dir_a;
    let ii_b = t.ii_torque_dir_b;
    let rhs = t.rhs;
    let pm = t.projected_mass;

    if tangent.x.is_nan() || tangent.y.is_nan() || pm.is_nan() || rhs.is_nan() {
        return;
    }

    let va_lin = solver_bodies.vel(ba).linear;
    let va_ang = solver_bodies.vel(ba).angular;
    let vb_lin = solver_bodies.vel(bb).linear;
    let vb_ang = solver_bodies.vel(bb).angular;

    if va_lin.x.is_nan()
        || va_lin.y.is_nan()
        || va_ang.is_nan()
        || vb_lin.x.is_nan()
        || vb_lin.y.is_nan()
        || vb_ang.is_nan()
    {
        return;
    }

    let dvel_uncapped = tangent.dot(vb_lin - va_lin) - td_a * va_ang + td_b * vb_ang + rhs;
    let dvel = if dvel_limit.is_finite() {
        dvel_uncapped.clamp(-dvel_limit, dvel_limit)
    } else {
        dvel_uncapped
    };

    // Unclamped friction impulse candidate
    let jt_candidate = t.impulse - pm * dvel;

    // Coulomb's Law: compare |jt| against j * static_friction threshold.
    // If below threshold → static friction (use jt directly, object not sliding).
    // If above threshold → dynamic friction (clamp to j * kinetic_friction).
    let j = normal_impulse.max(0.0);
    let static_limit = (j * t.static_friction_coeff).max(0.0);
    let dynamic_limit = (j * t.friction_coeff).max(0.0);

    let new_impulse = if jt_candidate.abs() <= static_limit {
        // Static regime: object not yet sliding, use full jt
        jt_candidate
    } else {
        // Dynamic regime: object sliding, clamp to kinetic friction
        jt_candidate.clamp(-dynamic_limit, dynamic_limit)
    };

    let dlambda = (new_impulse - t.impulse) * relax;
    t.impulse += dlambda;

    let im_a = solver_bodies.pose(ba).inv_mass;
    let im_b = solver_bodies.pose(bb).inv_mass;

    let va = solver_bodies.vel_mut(ba);
    va.linear -= tangent * (dlambda * im_a);
    va.angular -= ii_a * dlambda;

    let vb = solver_bodies.vel_mut(bb);
    vb.linear += tangent * (dlambda * im_b);
    vb.angular += ii_b * dlambda;
}
